HomeSearchBar( query = searchQuery, selectedFilter = songListFilter, onQueryChange = onSearchQueryChange, onSearch = onSearch, onFilterChange = onSongListFilterChange )
Box( modifier = Modifier .fillMaxWidth() .weight(1f), contentAlignment = Alignment.Center ) { HomeStateContent( uiState = uiState, filteredSongs = filteredSongs, favoriteSongIds = favoriteSongIds, songListFilter = songListFilter, searchQuery = searchQuery, previewPlaybackState = previewPlaybackState, onPreviewPlayPause = onPreviewPlayPause, onPreviewStop = onPreviewStop, onFavoriteToggle = onFavoriteToggle, onRetry = onRetry ) } } } } }
@Composable private fun HomeStateContent( uiState: MusicUiState, filteredSongs: List<Song>, favoriteSongIds: Set<String>, songListFilter: SongListFilter, searchQuery: String, previewPlaybackState: com.example.musicplayerlab.viewmodel.PreviewPlaybackState, onPreviewPlayPause: (Song) -> Unit, onPreviewStop: () -> Unit, onFavoriteToggle: (String) -> Unit, onRetry: () -> Unit ) { when (uiState) { MusicUiState.Idle -> CenteredMessageState( messageResId = R.string.home_idle_message )
MusicUiState.Loading -> LoadingState()
is MusicUiState.Success -> { if (filteredSongs.isEmpty()) { val emptyMessageResId = when { songListFilter == SongListFilter.FAVORITES_ONLY && searchQuery.isBlank() -> { R.string.home_favorites_empty_message } songListFilter == SongListFilter.FAVORITES_ONLY -> { R.string.home_favorites_search_empty_message } searchQuery.isBlank() -> R.string.home_empty_message else -> R.string.home_search_empty_message } EmptyState( messageResId = emptyMessageResId, onReload = onRetry ) } else { SongListSuccessState( songs = filteredSongs, previewPlaybackState = previewPlaybackState, onPreviewPlayPause = onPreviewPlayPause, onPreviewStop = onPreviewStop, favoriteSongIds = favoriteSongIds, onFavoriteToggle = onFavoriteToggle, onReload = onRetry ) } }
is MusicUiState.Error -> ErrorState( messageResId = uiState.messageResId, onRetry = onRetry ) } }

