@Composable private fun HomeStateContent( uiState: MusicUiState, filteredSongs: List<Song>, favoriteSongIds: Set<String>, songListFilter: SongListFilter, searchQuery: String, previewPlaybackState: com.example.musicplayerlab.viewmodel.PreviewPlaybackState, onPreviewPlayPause: (Song) -> Unit, onPreviewStop: () -> Unit, onFavoriteToggle: (String) -> Unit, onRetry: () -> Unit ) { when (uiState) { MusicUiState.Idle -> CenteredMessageState( messageResId = R.string.home_idle_message )
MusicUiState.Loading -> LoadingState()
is MusicUiState.Success -> { if (filteredSongs.isEmpty()) { val emptyMessageResId = when { songListFilter == SongListFilter.FAVORITES_ONLY && searchQuery.isBlank() -> { R.string.home_favorites_empty_message } songListFilter == SongListFilter.FAVORITES_ONLY -> { R.string.home_favorites_search_empty_message } searchQuery.isBlank() -> R.string.home_empty_message else -> R.string.home_search_empty_message } val supportingMessageResId = when { songListFilter == SongListFilter.FAVORITES_ONLY && searchQuery.isBlank() -> { R.string.home_favorites_empty_hint }
songListFilter == SongListFilter.FAVORITES_ONLY -> { R.string.home_favorites_search_empty_hint }
searchQuery.isBlank() -> R.string.home_empty_hint
else -> R.string.home_search_empty_hint } EmptyState( messageResId = emptyMessageResId, supportingMessageResId = supportingMessageResId, onReload = onRetry ) } else { SongListSuccessState( songs = filteredSongs, previewPlaybackState = previewPlaybackState, onPreviewPlayPause = onPreviewPlayPause, onPreviewStop = onPreviewStop, favoriteSongIds = favoriteSongIds, onFavoriteToggle = onFavoriteToggle, onReload = onRetry ) } }
is MusicUiState.Error -> ErrorState( messageResId = uiState.messageResId, supportingMessageResId = when (uiState.messageResId) { R.string.error_network_io, R.string.error_timeout, R.string.error_no_internet -> R.string.error_connection_hint
else -> null }, onRetry = onRetry ) } }
